%[text] ## Evaluation of DQN vs Brute Force Localization Precision (Trajectory)
%% Evaluation of DQN vs Brute Force Localization Precision on Random Positions (CDF)
% Executed until Done/Terminate conditions are met
clc; clear all; close all;

fprintf('=== Initializing Random Deployment Environment ===\n'); %[output:1fe83716]
% 1. Add required codebase folders to path
addingPathParentFolderByName('code');

% 2. Load Parameters
Parameters;  %[output:5f1a3a2b] %[output:27a23586] %[output:6a55ab5c] %[output:27b098c8] %[output:5fcd4218] %[output:3a93db55] %[output:72b1fdc7] %[output:273026da] %[output:97e3e275]

% 3. Run Calibration (Requires Parameters to be in the workspace)
Calibration; %[output:108cb54d]

% 4. Load the trained DQN agent
agent_path = fullfile('..', 'Dataset', 'dqn_agent_navigation_144_neurons_1_relu.mat');
if isfile(agent_path) %[output:group:27701c5b]
    load(agent_path, 'agent');
    fprintf('Trained agent successfully loaded.\n'); %[output:8bdc5572]
else
    error('Agent file not found. Ensure the Dataset folder is positioned correctly relative to this script.');
end %[output:group:27701c5b]

%%
%[text] ### DQN Agent and Brute Force (Trajectory)
%% Evaluation Setup
N_eval = 200; % Number of episodes (random positions) to evaluate

fprintf('Generating %d random Mobile Unit (MU) positions...\n', N_eval); %[output:0b73c879]
% err_dqn = zeros(N_eval, 1);
err_bf  = zeros(N_eval, length(N_vector), length(T_vector));
% steps_taken_dqn = zeros(N_eval, 1);

for i_n = 1:length(N_vector)
    % Meta-atom indexing — store inside EnvPars so closures don't depend on workspace
    n = (1:N_vector(i_n));
    n_y = ceil(n ./ N_x_vector(i_n));
    n_x = n - (n_y - 1) .* N_x_vector(i_n);
    n_psi = n;
    n_psi_y = ceil(n_psi ./ N_x_vector(i_n));
    n_psi_x = n_psi - (n_y - 1) .* N_x_vector(i_n);

    %Analytic FFT
    % Kernel 2D-DFT == TO BE REPLACED BY SIM 1
    G_func = @(n,n_psi) exp(-1i*2*pi*(n_psi_x(n_psi)-1)/N_x_vector(i_n).*(n_x(n)-1)).* ...
        exp(-1i*2*pi*(n_psi_y(n_psi)-1)/N_y_vector(i_n).*(n_y(n)-1));
    [n_psi_grid, n_s_grid] = ndgrid(1:N_vector(i_n), 1:N_vector(i_n));
    G = G_func(n_s_grid, n_psi_grid);

    for i_t = 1:length(T_vector)
        % Snapshots indexes for indexing psi_y and psi_x components of the electric
        % angle psi
        t_psi_idx = (1:T_vector(i_t));
        t_y = ceil(t_psi_idx ./ T_x_vector(i_t)) ;      % now in {0, ..., T_y - 1}
        t_x = t_psi_idx - (t_y-1) .* T_x_vector(i_t);   % now in {0, ..., T_x - 1}

        U_func = @(n_, t_n_) exp(1i * ( ...
            -2*pi*(n_x(n_)-1) .* (t_x(t_n_)-1) / (N_x_vector(i_n)*T_x_vector(i_t)) ...
            -2*pi*(n_y(n_)-1) .* (t_y(t_n_)-1) / (N_y_vector(i_n)*T_y_vector(i_t)) ));

        for i = 1:N_eval
            % if mod(i, 50) == 0
            %     fprintf('Evaluating position %d / %d...\n', i, N_eval);
            % end
            
            % 1. Generate a random MU position using the room boundaries from Calibration.m
            rx = EnvPars.MU_margin + (L_hall - 2*EnvPars.MU_margin) * rand();
            ry = EnvPars.MU_margin + (W_hall - 2*EnvPars.MU_margin) * rand();
            pos_MU_rand = [rx, ry, EnvPars.h_MU];
            
            % Compute true DOA for this random position using workspace position vars
            [psi_x_true, psi_y_true] = computePsiFromPos(pos_MU_rand, EnvPars);
            
            % 2. Mock a stationary "trajectory" up to the maximum safety limit
            EnvPars.psi_x_traj = repmat(psi_x_true, EnvPars.MaxStepsPerEpisode, 1);
            EnvPars.psi_y_traj = repmat(psi_y_true, EnvPars.MaxStepsPerEpisode, 1);
                                  
            % ---------------------------------------------------------
            % BRUTE FORCE EVALUATION (Optimal Benchmark)
            % ---------------------------------------------------------
            a_psi_x   = exp(1i * psi_x_true * ((1:N_x_vector(i_n))-1))';
            a_psi_y   = exp(1i * psi_y_true * ((1:N_y_vector(i_n))-1))';
            a_psi_x_y = kron(a_psi_y, a_psi_x);
             
            best_power = -inf;
            best_psi_x_est = 0;
            best_psi_y_est = 0;
             
            % Exhaustive search over all phase configurations
            for t_psi = 1:T_vector(i_t)
                v0  = U_func(1:N_vector(i_n), t_psi);
                Upsilon   = diag(v0');
                G_Upsilon = G * Upsilon;
                r   = sqrt(db2pow(EnvPars.SNR_dB)) * G_Upsilon * a_psi_x_y;
        
                power_vec = abs(r).^2;
                current_peak = max(power_vec);
        
                if current_peak > best_power
                    best_power = current_peak;
                    R = flipud(fliplr(reshape(abs(r), [N_x_vector(i_n), N_y_vector(i_n)])))';
                    [~, linear_idx] = max(R, [], 'all');
                    n_psi_x_max = ceil(linear_idx/N_x_vector(i_n));
                    n_psi_y_max = linear_idx-(n_psi_x_max-1)*N_x_vector(i_n);
                                        
                    % Map snapshot index to temporal coords
                    t_psi_x_max = t_x(t_psi);
                    t_psi_y_max = t_y(t_psi);
        
                    best_psi_x_est = mod(2*pi * (n_psi_x_max + (t_psi_x_max) / T_x_vector(i_t)) / N_x_vector(i_n), 2*pi);
                    best_psi_y_est = mod(2*pi * (n_psi_y_max + (t_psi_y_max) / T_y_vector(i_t)) / N_y_vector(i_n), 2*pi);
                end
            end
            
            pos_MU_rand_est = estimatePosFromAngles(psi_x_true, psi_y_true, EnvPars, pos_MU_rand);
            pos_est_bf = estimatePosFromAngles(best_psi_x_est, best_psi_y_est, EnvPars, pos_MU_rand_est);
            err_bf(i,i_n,i_t) = norm(pos_est_bf(1:2) - pos_MU_rand_est(1:2))*1e2; % cm
        end
    end
end

%%
%[text] ### Figures
prc95 = zeros(length(N_vector), length(T_vector));
% Percentiles
for i_n = 1:length(N_vector)
    for i_t = 1:length(T_vector)
        prc95(i_n,i_t) = quantile(err_bf(:,i_n,i_t), 0.95);
    end
end

