% 'Interpreter', 'latex', 'FontSize', font, 'BackgroundColor', 'white');

legend([p1 p2], legend_text, ... %[output:4e2db529]
    'Location', 'northeast', ... %[output:4e2db529]
    'Interpreter', 'latex', ... %[output:4e2db529]
    'FontSize', font, ... %[output:4e2db529]
    'NumColumns', 1); %[output:4e2db529]

set(gca, 'XTick', 1:length(N_vector)); %[output:4e2db529]
set(gca, 'XTickLabel', X_Tick_text, 'TickLabelInterpreter', 'latex'); %[output:4e2db529]
xtickangle(90); %[output:4e2db529]
xlabel('$N_x \times N_y$', 'Interpreter', 'latex'); %[output:4e2db529]
ylabel({'95th-pct $\psi_x$ error [cm]'}, 'Interpreter', 'latex'); %[output:4e2db529]
set(gca, 'FontSize', font); %[output:4e2db529]

% CDF
figure %[output:62f026c0]
% hold on
% h1 = cdfplot(err_dqn);
% set(h1, 'LineWidth', 1.5);
% grid on
h2 = cdfplot(err_bf(:,3,1)); %[output:62f026c0]
set(h2, 'LineWidth', 1.5); %[output:62f026c0]
grid on %[output:62f026c0]

xlim([0, 200]) %[output:62f026c0]
xlabel('Precision [cm]', 'Interpreter', 'latex', 'FontSize', 12); %[output:62f026c0]
ylabel('CDF', 'Interpreter', 'latex', 'FontSize', 12); %[output:62f026c0]
